// Анализ упавших N8N executions за последние 15 минут
const data = $input.first().json;
const executions = data?.data || [];

const now = new Date();
const cutoff = new Date(now.getTime() - 15 * 60 * 1000); // 15 минут

// Фильтруем только свежие ошибки
const recentFails = executions.filter(e => {
  const finished = e.stoppedAt || e.startedAt;
  if (!finished) return false;
  return new Date(finished) > cutoff;
});

if (recentFails.length === 0) {
  return [{ json: { hasErrors: false, count: 0, summary: 'Нет ошибок' } }];
}

// Группируем по workflow
const byWorkflow = {};
for (const e of recentFails) {
  const name = e.workflowData?.name || `WF#${e.workflowId}`;
  if (!byWorkflow[name]) {
    byWorkflow[name] = { count: 0, lastError: '', lastTime: '' };
  }
  byWorkflow[name].count++;

  // Попробовать извлечь сообщение ошибки
  const errMsg = e.data?.resultData?.error?.message 
    || e.data?.resultData?.lastNodeExecuted 
    || 'unknown error';
  byWorkflow[name].lastError = errMsg;
  byWorkflow[name].lastTime = e.stoppedAt || e.startedAt;
}

// Формируем отчёт
const lines = Object.entries(byWorkflow).map(([name, info]) => {
  const count = info.count > 1 ? ` (${info.count}x)` : '';
  const time = new Date(info.lastTime).toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' });
  return `• ${name}${count} — ${info.lastError} [${time}]`;
});

return [{
  json: {
    hasErrors: true,
    count: recentFails.length,
    summary: lines.join('\n'),
    workflows: byWorkflow,
    timestamp: now.toISOString()
  }
}];

